import java.util.Scanner;
import java.util.Arrays;

public class SecureBufferExample {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter a string: ");
        String input = scanner.nextLine();

        // Secure buffer handling
        int maxLength = 10; // Define maximum buffer size
        byte[] buffer = new byte[maxLength];

        if (input.length() <= maxLength) {
            System.arraycopy(input.getBytes(), 0, buffer, 0, input.length());
            System.out.println("Input copied to buffer securely.");
        } else {
            System.out.println("Input exceeds maximum length. Please enter a shorter string.");
        }

        // Optional: Clearing sensitive data in memory
        Arrays.fill(buffer, (byte) 0);

    }
}

